UPDATE wa_ai_agents
SET knowledge_base = '{"empresa":{"nombre":"Nineteen Custom","rubro":"textil","descripcion":"Empresa textil venezolana especializada en la confeccion de prendas personalizadas. NO vende telas ni hilos como materia prima, vende prendas ya confeccionadas y personalizadas."},"productos":{"categorias":["Franelas","Chemises","Jersey","Camisas","Leggins","Banderines"],"tipo":"Prendas confeccionadas personalizables (camisetas, chemises, uniformes, ropa deportiva personalizada)","nota":"No vendemos telas ni hilos como materia prima"},"servicios_adicionales":["Diseno grafico","Diseno de logotipos","Confeccion de prendas a medida"],"precios":{"nota":"Los precios varian segun el producto, cantidad y personalizacion. Siempre cotizar con el equipo de ventas antes de dar cifras","minimo_compra":"No hay minimo de precio de compra","pedido_minimo":"1 pieza"},"metodos_pago":{"formas":["Efectivo","Transferencia bancaria","Pago movil","Zelle"],"monedas":["Bolivares","Dolares"],"modalidades":["Contado","Credito (consultar condiciones con ventas)"]},"horario":{"dias":"Lunes a Viernes","manana":"8:30 AM - 12:00 PM","tarde":"1:00 PM - 5:30 PM","nota":"Fines de semana y feriados no hay atencion"},"envios":{"cobertura":"Toda Venezuela","costo_desde":"15 USD en adelante segun destino","tiempo_entrega":"Depende de la cantidad de prendas, desde 1 dia"},"contacto":{"telefono":"+58 426-8730136","email":"info@nineteengreen.com","instagram":"@nineteencustom","direccion":"Sector El Carmen, Av 13, El Vigia, Merida, Venezuela"},"faq":[{"pregunta":"Que precio tienen los productos?","respuesta":"Los precios dependen del tipo de prenda, cantidad y nivel de personalizacion. Por favor indicanos que necesitas (tipo de prenda, cantidad, si llevara diseno/logo) y con gusto te cotizamos."},{"pregunta":"Que tipos de prendas venden?","respuesta":"Vendemos prendas confeccionadas y personalizables: franelas, chemises, jersey, camisas, leggins y banderines. Tambien ofrecemos diseno grafico y diseno de logotipos."},{"pregunta":"Cuales son las formas de pago?","respuesta":"Aceptamos efectivo, transferencia bancaria, pago movil y Zelle, tanto en bolivares como en dolares. Manejamos ventas de contado y credito (consultar condiciones con nuestro equipo)."},{"pregunta":"Dan garantia?","respuesta":"Consultar con el equipo de ventas las condiciones especificas de garantia segun el producto."},{"pregunta":"Hacen envios a toda Venezuela?","respuesta":"Si, enviamos a toda Venezuela. El costo de envio desde 15 USD segun el destino. El tiempo de entrega depende de la cantidad de prendas, desde 1 dia."}]}'
